DROP VIEW "milestone";--> statement-breakpoint
CREATE VIEW "milestone" AS (select "aggregate_id" as "id", (array_agg("payload"#>>'{changes,project_id,to}' ORDER BY "version" DESC) FILTER (WHERE jsonb_exists("payload"#>'{changes,project_id}', 'to')))[1]::uuid as "project_id", (array_agg("payload"#>>'{changes,title,to}' ORDER BY "version" DESC) FILTER (WHERE jsonb_exists("payload"#>'{changes,title}', 'to')))[1] as "title", ((array_agg("payload"#>>'{changes,cost,to}' ORDER BY "version" DESC) FILTER (WHERE jsonb_exists("payload"#>'{changes,cost}', 'to')))[1])::numeric as "cost", (array_agg("payload"#>>'{changes,currency,to}' ORDER BY "version" DESC) FILTER (WHERE jsonb_exists("payload"#>'{changes,currency}', 'to')))[1] as "currency", (array_agg("payload"#>>'{changes,state,to}' ORDER BY "version" DESC) FILTER (WHERE jsonb_exists("payload"#>'{changes,state}', 'to')))[1] as "state", ((array_agg("payload"#>>'{changes,due_at,to}' ORDER BY "version" DESC) FILTER (WHERE jsonb_exists("payload"#>'{changes,due_at}', 'to')))[1])::timestamp with time zone as "due_at", (array_agg("recorded_at" ORDER BY "version" ASC))[1] as "created_at" from "event" where "event"."aggregate_type" = 'milestone' group by "event"."aggregate_id");